{
  "children": [
    {
      "name": "ParseCommand",
      "purpose": "Validate and parse the command string to determine the operation type.",
      "behavior": "Check if command is one of 'place', 'cancel', 'track'. If invalid, return error. Otherwise, pass command type forward.",
      "boundary": {
        "in_scope": [
          "command validation",
          "command type extraction"
        ],
        "out_of_scope": [
          "order data validation",
          "business logic execution"
        ]
      },
      "preconditions": [
        "command is a string"
      ],
      "postconditions": [
        "parsed_command is one of 'place', 'cancel', 'track' or error"
      ],
      "guarantees": [
        "Returns error if command is invalid"
      ],
      "composition_role": "validate",
      "stop_decompose": true,
      "stop_reason": "Pure validation function",
      "inputs": [
        {
          "name": "command",
          "type": "str",
          "description": "Order command string",
          "source": "parent input"
        }
      ],
      "outputs": [
        {
          "name": "parsed_command",
          "type": "str",
          "description": "Validated command type: 'place', 'cancel', 'track', or error message",
          "consumer": "parent"
        }
      ],
      "signature": "def ParseCommand(command: str) -> str"
    },
    {
      "name": "ValidateOrderData",
      "purpose": "Validate the order_data structure and required fields based on command type.",
      "behavior": "Check that order_data contains required fields (e.g., items for place, order_id for cancel/track). Return validation result.",
      "boundary": {
        "in_scope": [
          "field presence",
          "data type checks"
        ],
        "out_of_scope": [
          "business rule validation",
          "database access"
        ]
      },
      "preconditions": [
        "order_data is a dict"
      ],
      "postconditions": [
        "validation_result indicates pass/fail"
      ],
      "guarantees": [
        "Does not modify any state"
      ],
      "composition_role": "validate",
      "stop_decompose": true,
      "stop_reason": "Pure validation function",
      "inputs": [
        {
          "name": "command",
          "type": "str",
          "description": "Parsed command type",
          "source": "ParseCommand output"
        },
        {
          "name": "order_data",
          "type": "dict",
          "description": "Order payload",
          "source": "parent input"
        }
      ],
      "outputs": [
        {
          "name": "validation_result",
          "type": "dict",
          "description": "Dict with 'valid' (bool) and 'error' (str, optional)",
          "consumer": "parent"
        }
      ],
      "signature": "def ValidateOrderData(command: str, order_data: dict) -> dict"
    },
    {
      "name": "PlaceOrder",
      "purpose": "Execute the 'place' command: validate items, charge payment, reserve inventory, create order, send notification.",
      "behavior": "Sequentially: check item existence and stock, charge payment, reserve inventory, create order record, send notification. On failure, rollback previous steps.",
      "boundary": {
        "in_scope": [
          "item validation",
          "payment charging",
          "inventory reservation",
          "order creation",
          "notification sending"
        ],
        "out_of_scope": [
          "cancel logic",
          "track logic"
        ]
      },
      "preconditions": [
        "command is 'place'",
        "order_data is valid"
      ],
      "postconditions": [
        "If success: order created, payment charged, inventory reserved. If failure: all changes rolled back."
      ],
      "guarantees": [
        "Atomicity: all or nothing"
      ],
      "composition_role": "execute",
      "stop_decompose": false,
      "stop_reason": "Complex multi-step process, can be further decomposed",
      "inputs": [
        {
          "name": "order_data",
          "type": "dict",
          "description": "Order payload with items, payment_method, shipping_address",
          "source": "parent input"
        }
      ],
      "outputs": [
        {
          "name": "order_result",
          "type": "dict",
          "description": "Result dict with success (bool), order_id (str), status (str), message (str)",
          "consumer": "parent"
        }
      ],
      "signature": "def PlaceOrder(order_data: dict) -> dict"
    },
    {
      "name": "CancelOrder",
      "purpose": "Execute the 'cancel' command: verify order exists and not shipped, refund payment, restore inventory, update order status.",
      "behavior": "Check order existence and status, refund payment, restore reserved inventory, update order status to cancelled. Rollback on failure.",
      "boundary": {
        "in_scope": [
          "order verification",
          "payment refund",
          "inventory restoration",
          "status update"
        ],
        "out_of_scope": [
          "place logic",
          "track logic"
        ]
      },
      "preconditions": [
        "command is 'cancel'",
        "order_data contains order_id"
      ],
      "postconditions": [
        "If success: order cancelled, payment refunded, inventory restored. If failure: no changes."
      ],
      "guarantees": [
        "Atomicity: all or nothing"
      ],
      "composition_role": "execute",
      "stop_decompose": false,
      "stop_reason": "Complex multi-step process, can be further decomposed",
      "inputs": [
        {
          "name": "order_data",
          "type": "dict",
          "description": "Order payload with order_id",
          "source": "parent input"
        }
      ],
      "outputs": [
        {
          "name": "order_result",
          "type": "dict",
          "description": "Result dict with success (bool), order_id (str), status (str), message (str)",
          "consumer": "parent"
        }
      ],
      "signature": "def CancelOrder(order_data: dict) -> dict"
    },
    {
      "name": "TrackOrder",
      "purpose": "Execute the 'track' command: return current order status and estimated delivery time.",
      "behavior": "Look up order by order_id in orders store, retrieve status and estimated delivery time, return result.",
      "boundary": {
        "in_scope": [
          "order lookup",
          "status retrieval",
          "delivery time estimation"
        ],
        "out_of_scope": [
          "place logic",
          "cancel logic"
        ]
      },
      "preconditions": [
        "command is 'track'",
        "order_data contains order_id"
      ],
      "postconditions": [
        "Order data is read, not modified"
      ],
      "guarantees": [
        "No side effects"
      ],
      "composition_role": "query",
      "stop_decompose": true,
      "stop_reason": "Simple read operation",
      "inputs": [
        {
          "name": "order_data",
          "type": "dict",
          "description": "Order payload with order_id",
          "source": "parent input"
        }
      ],
      "outputs": [
        {
          "name": "order_result",
          "type": "dict",
          "description": "Result dict with success (bool), order_id (str), status (str), message (str) including delivery time",
          "consumer": "parent"
        }
      ],
      "signature": "def TrackOrder(order_data: dict) -> dict"
    },
    {
      "name": "CheckItemAvailability",
      "purpose": "Validate that all items in the order exist and have sufficient stock (including reserved count).",
      "behavior": "For each item in order_data['items'], check inventory store for existence and stock_count - reserved_count >= quantity. Return boolean and error message.",
      "boundary": {
        "in_scope": [
          "item existence check",
          "stock sufficiency check"
        ],
        "out_of_scope": [
          "payment",
          "inventory reservation"
        ]
      },
      "preconditions": [
        "items is a non-empty list"
      ],
      "postconditions": [
        "No state changes"
      ],
      "guarantees": [
        "Read-only operation"
      ],
      "composition_role": "validate",
      "stop_decompose": true,
      "stop_reason": "Pure validation function",
      "inputs": [
        {
          "name": "items",
          "type": "list",
          "description": "List of items with product_id and quantity",
          "source": "PlaceOrder input (order_data['items'])"
        }
      ],
      "outputs": [
        {
          "name": "availability_result",
          "type": "dict",
          "description": "Dict with 'available' (bool) and 'error' (str, optional)",
          "consumer": "PlaceOrder"
        }
      ],
      "signature": "def CheckItemAvailability(items: list) -> dict"
    },
    {
      "name": "ChargePayment",
      "purpose": "Charge the payment for the order using the specified payment method.",
      "behavior": "Create a payment record with amount calculated from items, charge via payment gateway (simulated), update payment status. Return payment_id or failure.",
      "boundary": {
        "in_scope": [
          "payment amount calculation",
          "payment gateway call",
          "payment record creation"
        ],
        "out_of_scope": [
          "inventory",
          "order creation"
        ]
      },
      "preconditions": [
        "Items are available"
      ],
      "postconditions": [
        "If success: payment record created with status 'charged'. If failure: no payment record."
      ],
      "guarantees": [
        "Payment is charged only once"
      ],
      "composition_role": "execute",
      "stop_decompose": true,
      "stop_reason": "Atomic payment operation",
      "inputs": [
        {
          "name": "items",
          "type": "list",
          "description": "List of items with product_id and quantity",
          "source": "PlaceOrder input (order_data['items'])"
        },
        {
          "name": "payment_method",
          "type": "str",
          "description": "Payment method string",
          "source": "PlaceOrder input (order_data['payment_method'])"
        }
      ],
      "outputs": [
        {
          "name": "payment_result",
          "type": "dict",
          "description": "Dict with success (bool), payment_id (str, optional), error (str, optional)",
          "consumer": "PlaceOrder"
        }
      ],
      "signature": "def ChargePayment(items: list, payment_method: str) -> dict"
    },
    {
      "name": "ReserveInventory",
      "purpose": "Reserve inventory for the order items by incrementing reserved_count.",
      "behavior": "For each item, update inventory store: reserved_count += quantity. Return success or failure with rollback capability.",
      "boundary": {
        "in_scope": [
          "inventory reservation update"
        ],
        "out_of_scope": [
          "payment",
          "order creation"
        ]
      },
      "preconditions": [
        "Payment charged successfully"
      ],
      "postconditions": [
        "If success: reserved_count increased for each item. If failure: no changes."
      ],
      "guarantees": [
        "Atomic update across items"
      ],
      "composition_role": "mutate",
      "stop_decompose": true,
      "stop_reason": "Atomic inventory mutation",
      "inputs": [
        {
          "name": "items",
          "type": "list",
          "description": "List of items with product_id and quantity",
          "source": "PlaceOrder input (order_data['items'])"
        }
      ],
      "outputs": [
        {
          "name": "reservation_result",
          "type": "dict",
          "description": "Dict with success (bool), error (str, optional)",
          "consumer": "PlaceOrder"
        }
      ],
      "signature": "def ReserveInventory(items: list) -> dict"
    },
    {
      "name": "CreateOrderRecord",
      "purpose": "Create the order record in the orders data store with status 'confirmed'.",
      "behavior": "Generate order_id if not provided, store order details including items, payment_id, shipping_address, status, created_at.",
      "boundary": {
        "in_scope": [
          "order record creation",
          "order_id generation"
        ],
        "out_of_scope": [
          "inventory",
          "payment"
        ]
      },
      "preconditions": [
        "Inventory reserved"
      ],
      "postconditions": [
        "Order record exists in orders store with status 'confirmed'"
      ],
      "guarantees": [
        "Order record is created atomically"
      ],
      "composition_role": "execute",
      "stop_decompose": true,
      "stop_reason": "Atomic database write",
      "inputs": [
        {
          "name": "order_data",
          "type": "dict",
          "description": "Order payload with items, shipping_address",
          "source": "PlaceOrder input (order_data)"
        },
        {
          "name": "payment_id",
          "type": "str",
          "description": "Payment identifier",
          "source": "ChargePayment output"
        }
      ],
      "outputs": [
        {
          "name": "order_record_result",
          "type": "dict",
          "description": "Dict with success (bool), order_id (str, optional), error (str, optional)",
          "consumer": "PlaceOrder"
        }
      ],
      "signature": "def CreateOrderRecord(order_data: dict, payment_id: str) -> dict"
    },
    {
      "name": "SendNotification",
      "purpose": "Send a confirmation notification to the customer (simulated).",
      "behavior": "Compose and send notification message based on order details. Log notification. Return success.",
      "boundary": {
        "in_scope": [
          "notification composition",
          "notification sending"
        ],
        "out_of_scope": [
          "order creation",
          "inventory"
        ]
      },
      "preconditions": [
        "Order record created"
      ],
      "postconditions": [
        "Notification sent (simulated)"
      ],
      "guarantees": [
        "No side effects on order or inventory"
      ],
      "composition_role": "execute",
      "stop_decompose": true,
      "stop_reason": "Simple notification operation",
      "inputs": [
        {
          "name": "order_id",
          "type": "str",
          "description": "Order identifier",
          "source": "CreateOrderRecord output"
        },
        {
          "name": "order_data",
          "type": "dict",
          "description": "Order payload with shipping_address",
          "source": "PlaceOrder input (order_data)"
        }
      ],
      "outputs": [
        {
          "name": "notification_result",
          "type": "dict",
          "description": "Dict with success (bool), error (str, optional)",
          "consumer": "PlaceOrder"
        }
      ],
      "signature": "def SendNotification(order_id: str, order_data: dict) -> dict"
    }
  ],
  "interface_preservation": {
    "parent_inputs_covered_by": {
      "command": "ParseCommand",
      "order_data": "ValidateOrderData, PlaceOrder, CancelOrder, TrackOrder"
    },
    "parent_outputs_produced_by": {
      "order_result": "PlaceOrder, CancelOrder, TrackOrder"
    }
  },
  "dataflow_edges": [
    {
      "from_node": "parent",
      "from_output": "command",
      "to_node": "ParseCommand",
      "to_input": "command",
      "note": "Pass command for validation"
    },
    {
      "from_node": "ParseCommand",
      "from_output": "parsed_command",
      "to_node": "ValidateOrderData",
      "to_input": "command",
      "note": "Pass validated command for data validation"
    },
    {
      "from_node": "parent",
      "from_output": "order_data",
      "to_node": "ValidateOrderData",
      "to_input": "order_data",
      "note": "Pass order data for validation"
    },
    {
      "from_node": "parent",
      "from_output": "order_data",
      "to_node": "PlaceOrder",
      "to_input": "order_data",
      "note": "Pass order data for place execution"
    },
    {
      "from_node": "parent",
      "from_output": "order_data",
      "to_node": "CancelOrder",
      "to_input": "order_data",
      "note": "Pass order data for cancel execution"
    },
    {
      "from_node": "parent",
      "from_output": "order_data",
      "to_node": "TrackOrder",
      "to_input": "order_data",
      "note": "Pass order data for track execution"
    },
    {
      "from_node": "PlaceOrder",
      "from_output": "order_data['items']",
      "to_node": "CheckItemAvailability",
      "to_input": "items",
      "note": "Pass items for availability check"
    },
    {
      "from_node": "PlaceOrder",
      "from_output": "order_data['items']",
      "to_node": "ChargePayment",
      "to_input": "items",
      "note": "Pass items for payment calculation"
    },
    {
      "from_node": "PlaceOrder",
      "from_output": "order_data['payment_method']",
      "to_node": "ChargePayment",
      "to_input": "payment_method",
      "note": "Pass payment method"
    },
    {
      "from_node": "PlaceOrder",
      "from_output": "order_data['items']",
      "to_node": "ReserveInventory",
      "to_input": "items",
      "note": "Pass items for inventory reservation"
    },
    {
      "from_node": "ChargePayment",
      "from_output": "payment_id",
      "to_node": "CreateOrderRecord",
      "to_input": "payment_id",
      "note": "Pass payment ID for order record"
    },
    {
      "from_node": "PlaceOrder",
      "from_output": "order_data",
      "to_node": "CreateOrderRecord",
      "to_input": "order_data",
      "note": "Pass order data for record creation"
    },
    {
      "from_node": "CreateOrderRecord",
      "from_output": "order_id",
      "to_node": "SendNotification",
      "to_input": "order_id",
      "note": "Pass order ID for notification"
    },
    {
      "from_node": "PlaceOrder",
      "from_output": "order_data",
      "to_node": "SendNotification",
      "to_input": "order_data",
      "note": "Pass order data for notification"
    },
    {
      "from_node": "PlaceOrder",
      "from_output": "order_result",
      "to_node": "parent",
      "to_input": "order_result",
      "note": "Return result to parent"
    },
    {
      "from_node": "CancelOrder",
      "from_output": "order_result",
      "to_node": "parent",
      "to_input": "order_result",
      "note": "Return result to parent"
    },
    {
      "from_node": "TrackOrder",
      "from_output": "order_result",
      "to_node": "parent",
      "to_input": "order_result",
      "note": "Return result to parent"
    }
  ]
}
